parameters.jsCode:
const upcomingItems = $('Query Upcoming Tasks').all().map(item => item.json).filter(task => task && task.id);
const overdueItems = $('Query Overdue Tasks').all().map(item => item.json).filter(task => task && task.id);

const groups = new Map();

function getGroup(task) {
  const slackUserId = task.slack_user_id;
  if (!slackUserId) return null;

  if (!groups.has(slackUserId)) {
    groups.set(slackUserId, {
      slack_user_id: slackUserId,
      assignee_name: task.name || task.email || 'there',
      email: task.email || null,
      overdue: [],
      upcoming: []
    });
  }

  return groups.get(slackUserId);
}

function formatDate(value) {
  if (!value) return 'No deadline';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toISOString().replace('T', ' ').slice(0, 16) + ' UTC';
}

function formatTask(task) {
  const priority = task.priority ? task.priority.toUpperCase() : 'MEDIUM';
  const title = task.title || 'Untitled task';
  return `• [${priority}] ${title} — due ${formatDate(task.deadline)}`;
}

for (const task of overdueItems) {
  const group = getGroup(task);
  if (group) group.overdue.push(task);
}

for (const task of upcomingItems) {
  const group = getGroup(task);
  if (group) group.upcoming.push(task);
}

const reminderGroups = [...groups.values()].map(group => {
  const overdueList = group.overdue.length > 0
    ? group.overdue.map(formatTask).join('\n')
    : '_No overdue tasks_';
  const upcomingList = group.upcoming.length > 0
    ? group.upcoming.map(formatTask).join('\n')
    : '_No upcoming tasks due in the next 48 hours_';

  return {
    json: {
      slack_user_id: group.slack_user_id,
      assignee_name: group.assignee_name,
      email: group.email,
      overdue_count: group.overdue.length,
      upcoming_count: group.upcoming.length,
      overdue_list: overdueList,
      upcoming_list: upcomingList,
      message: `⏰ *Daily Task Reminder*\n\n*Overdue (${group.overdue.length}):*\n${overdueList}\n\n*Upcoming (${group.upcoming.length}):*\n${upcomingList}`
    }
  };
});

if (reminderGroups.length === 0) {
  return [{
    json: {
      no_reminders: true,
      overdue_count: overdueItems.length,
      upcoming_count: upcomingItems.length,
      skipped_without_slack: [...overdueItems, ...upcomingItems].filter(task => !task.slack_user_id).length
    }
  }];
}

return reminderGroups;

