={{ {
  "workflow_name": "TASK__SendReminders",
  "execution_id": $execution.id,
  "log_type": "action",
  "action": "task_reminders_sent",
  "input_payload": {
    "schedule": "0 9 * * *",
    "window_hours": 48
  },
  "output_payload": {
    "assignee_groups": $('Group by Assignee').all().filter(item => !item.json.no_reminders).length,
    "overdue_count": $('Group by Assignee').all().reduce((sum, item) => sum + (item.json.overdue_count || 0), 0),
    "upcoming_count": $('Group by Assignee').all().reduce((sum, item) => sum + (item.json.upcoming_count || 0), 0),
    "skipped_without_slack": $('Group by Assignee').first().json.no_reminders ? $('Group by Assignee').first().json.skipped_without_slack : 0
  },
  "status": "success"
} }}
